            this.parent = Array(size).fill(0).map((_, i) => i);
            this.rank = Array(size).fill(0);
        }

        find(x: number): number {
            if (this.parent[x] !== x) {
                this.parent[x] = this.find(this.parent[x]);
            }
            return this.parent[x];
        }

        union(x: number, y: number): boolean {
            const xRoot = this.find(x);
            const yRoot = this.find(y);

            if (xRoot === yRoot) {
                return false; // Already connected
            }

            if (this.rank[xRoot] < this.rank[yRoot]) {
                this.parent[xRoot] = yRoot;
            } else {
                this.parent[yRoot] = xRoot;
                if (this.rank[xRoot] === this.rank[yRoot]) {
                    this.rank[xRoot]++;
                }
            }
            return true;
        }
    }

    // Initialize Union-Find
    const uf = new UnionFind(n);

    // Track the number of connected components and the maximum edge weight in each component
    let components = n;
    let maxEdge = 0;

    // Process edges in increasing order of weight
    for (const [u, v, w] of edges) {
        if (uf.union(u, v)) {
            components--;
            maxEdge = Math.max(maxEdge, w);
        }
    }

    // If k is 1, the answer is the maximum edge weight in the entire graph
    if (k === 1) {
        return maxEdge;
